124→impl Debugger {
125→    fn load_binary(&mut self, _ctx: &Context<Self>) {
126→        let mut asm = Assembler::new();
127→        let result = asm.assemble(self.tier.assembly());
128→
129→        if !result.errors.is_empty() {
130→            self.output = "Assembly errors:\n".to_string();
131→            for e in &result.errors {
132→                self.output.push_str(e);
133→                self.output.push('\n');
134→            }
135→            return;
136→        }
137→
138→        // Store assembly metadata for panels.
139→        self.labels = result.labels.clone();
140→        self.reverse_labels = result
141→            .labels
142→            .iter()
143→            .map(|(name, &addr)| (addr, name.clone()))
144→            .collect();
145→        self.assembled_lines = result.lines.clone();
146→        self.program_end = result.bytes.len() as u32;
147→        self.dict_entries = self.build_dict_entries();
148→
149→        self.emulator.hard_reset();
150→        self.emulator.load_program(0, &result.bytes);
151→        self.emulator.load_program_extent(result.bytes.len() as u32);
152→        self.emulator.set_pc(0);
153→        self.output.clear();
154→        self.halted = false;
155→        self.prev_regs = [0; 8];
156→        self.prev_pc = 0;
157→        self.uart_rx_queue.clear();
158→        self.selected_word = None;
159→        self.switch_pressed = false;
160→        self.selected_demo = None;
161→
162→        // Start paused — debugger mode.
163→        self.running = false;
164→        self.emulator.pause();
165→    }
166→
167→    fn schedule_tick(&mut self, ctx: &Context<Self>) {
168→        let link = ctx.link().clone();
169→        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
170→            link.send_message(Msg::Tick);
171→        }));
172→    }
173→
174→    fn snapshot_regs(&self) -> [u32; 8] {
175→        let snap = self.emulator.snapshot();
176→        snap.regs
177→    }
178→
179→    fn read_data_stack(&self) -> Vec<u32> {
180→        let sp = self.emulator.snapshot().regs[4]; // sp = r4
181→        let stack_top = self.stack_size.initial_sp();
182→        let mut cells = Vec::new();
183→        let mut addr = stack_top;
184→        // Stack grows downward; entries are from stack_top-3 down to sp.
185→        while addr > sp && cells.len() < 64 {
186→            addr -= CELL;
187→            let val = self.emulator.read_word(addr);
188→            cells.push(val & 0xFFFFFF);
189→        }
190→        cells.reverse(); // bottom of stack first
191→        cells
192→    }
193→
194→    fn read_return_stack(&self) -> Vec<u32> {
195→        let rsp = self.emulator.snapshot().regs[1]; // r1 = RSP
196→        let rstack_base: u32 = 0x0F0000;
197→        let mut cells = Vec::new();
198→        // Only walk when RSP has been initialized to the return stack region
199→        if rsp == 0 || rsp >= rstack_base {
