360→                }
361→                self.send_input();
362→                self.status = "Evaluating...".into();
363→                self.waiting_for_input = false;
364→                if !self.running {
365→                    self.emulator.resume();
366→                    self.running = true;
367→                    ctx.link().send_message(Msg::Tick);
